sql:
SELECT value
FROM prediction_restrictions
WHERE prediction_restriction_id = 1;

SELECT e.entity_name, e.area, e.population, dt.data_type_name, dt.unit
FROM entities e
CROSS JOIN data_types dt;

SELECT value
FROM prediction_restrictions
WHERE prediction_id = 0;

external_knowledge:
- 'turn of the millennium' refers to the year 2000;
- 'numerical data' corresponds to 'number' data type;
- 'forecast identifiers' means 'prediction_id';
- 'city of Montreal' refers to 'entity_name' = 'Montreal';

sql:
SELECT FLOOR(value) AS rounded_value
FROM prediction_restrictions
WHERE prediction_id = 1;

SELECT * FROM predictions
WHERE entity_id = 0 AND value > 100
ORDER BY value DESC;
